#include <stdio.h>
int main() {
    int M, N;
    scanf("%d", &M);
    int books[M];
    for (int i = 0; i < M; i++) {
        scanf("%d", &books[i]);
    }
    scanf("%d", &N);
    for (int i = 0; i < N; i++) {
        int pos;
        scanf("%d", &pos);
        printf("%d\n", books[pos - 1]);
        // Remove the borrowed book from the shelf
        for (int j = pos - 1; j < M - 1; j++) {
            books[j] = books[j + 1];
        }
        M--;
    }
    return 0;
}

